sql:
SELECT AVG(age) AS average_age, MAX(age) AS max_age
FROM age_data
WHERE age_group = '26-35';

external_knowledge:
- "consenting adults" refers to participants who have a non-null consent date; 
- "study number one" refers to the study with ID 1;
- "initial survey question" refers to the question with ID 0.

sql:
SELECT AVG(age) AS average_age
FROM participants
WHERE age > 25 AND consent_date > '2022-01-01';

